<template>
  <div class="add-material">
    <!-- 搜索框 -->
    <el-row style="height: 4vh">
      <el-col :span="24">
        <el-input size="mini" placeholder="查询" v-model="queryParams.name" class="input-with-select">
          <el-button slot="append" icon="el-icon-search" @click="handleSearch" />
        </el-input>
      </el-col>
    </el-row>

    <el-row :gutter="10" class="main-content-row">
      <el-col :span="6" class="sidebar-col">
        <!-- 左侧分类导航 -->
        <SlideLeftTwo
          ref="slideLeftRef"
          :categoryList="categoryList"
          @handleParams="handleQuery"
          :collectionStatus="true"
          @handleCollectionList="collectionClick"
          :lasterVersion="lasterVersion"
          :currentVersion="currentVersion"
        />
      </el-col>

      <!-- 右侧素材展示区（3列网格） -->
      <el-col :span="18" class="content-col">
        <div class="content" :infinite-scroll-distance="10" :infinite-scroll-immediate="false" v-infinite-scroll="loadList">
          <div class="content-image" v-for="item in materialAllList" :key="String(item.id)">
            <img :src="item.thumbnail" @click="handleDownload(item)" style="width: 100%; height: 100%; object-fit: cover; border-radius: 10%" />
            <div class="icon-container">
              <i
                @click.stop="handleCollection(item, 0)"
                class="el-icon-star-on"
                style="font-size: 25px; color: orange"
                v-if="item.params !== null && item.params.collectionId !== null"
              ></i>
              <i v-else @click.stop="handleCollection(item, 1)" class="el-icon-star-off" style="font-size: 25px; color: white"></i>
            </div>
            <div class="price-tag" v-if="item.discountAmount">限时{{ item.discountAmount }}币</div>
            <div class="price-tag" v-else>{{ item.normalAmount }}币</div>
          </div>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import SlideLeftTwo from '@/components/SlideLeftTwo.vue';
import { getProductList, getCollectionList, addCollection, deleteCollection, getCategoryList } from '@/api/main';
import { downloadAndOpen } from '@/utils/cepio';
import { addConsumeRecord } from '@/api/psdFile';

export default {
  name: 'MaterialList',
  components: {
    SlideLeftTwo
  },
  props: {
    userInfo: {
      type: Object,
      default: () => ({})
    },
    categoryParentId: {
      type: String,
      default: null
    },
    lasterVersion: {
      type: String,
      default: null
    },
    currentVersion: {
      type: String,
      default: null
    }
  },
  data() {
    return {
      totalCount: 0,
      categoryList: [],
      materialList: [],
      materialAllList: [],
      queryParams: {
        firstCategoryId: this.categoryParentId,
        categoryId: null,
        thirdCategoryId: null,
        fourCategoryId: null,
        name: null,
        pageNum: 1,
        pageSize: 20
      }
    };
  },
  created() {
    this.getCategories();
  },
  methods: {
    async getCategories() {
      const params = { parentId: this.categoryParentId };
      const response = await getCategoryList(params);
      this.categoryList = response.data || [];
    },
    async handleQuery(params) {
      this.queryParams = { ...params, firstCategoryId: this.categoryParentId, pageNum: 1, pageSize: 20 }; // 更新查询参数
      await this.getMaterials();
      this.materialAllList = this.materialList;
    },
    async getMaterials() {
      try {
        const response = await getProductList(this.queryParams);
        this.totalCount = response.data && response.data.total ? response.data.total : 0;
        this.materialList = response.data && response.data.records ? response.data.records : [];
      } catch (error) {
        console.error('获取素材列表失败:', error);
        this.materialList = [];
      }
    },
    async handleCollection(item, type) {
      if (type === 1) {
        let response = await addCollection({ productId: item.id });
        this.$message.success('收藏成功');
        this.$set(item, 'params', { ...item.params, collectionId: response.data });
      } else if (type === 0) {
        await deleteCollection({ id: item.params.collectionId });
        this.$set(item, 'params', null);
        this.$message.success('取消成功');
      }
    },
    async collectionClick() {
      await this.getCollections();
      this.materialAllList = this.materialList;
    },
    async getCollections() {
      this.queryParams.pageNum = 1;
      let response = await getCollectionList();
      this.materialList = response.data;
    },
    async loadList() {
      if (this.materialAllList.length >= this.totalCount) {
        return; // 没有更多数据了
      }
      this.queryParams.pageNum += 1;
      await this.getMaterials();
      this.materialAllList = this.materialAllList.concat(this.materialList);
    },
    async handleSearch() {
      this.queryParams.pageNum = 1;
      this.queryParams.categoryId = null;
      this.queryParams.thirdCategoryId = null;
      this.queryParams.fourCategoryId = null;
      await this.getMaterials();
      this.materialAllList = this.materialList;
    },
    async handleDownload(item) {
      let coinTemp = this.userInfo.coin ? this.userInfo.coin : 0;
      let buyAmount = item.discountAmount ? item.discountAmount : item.normalAmount;
      if (coinTemp < buyAmount) {
        this.$message.error('余额不足，请先充值');
      } else {
        let params = {
          productId: item.id
        };
        addConsumeRecord(params).then((res) => {
          if (res.code === 200) {
            this.$emit('refreshUserInfo', null); // 通知父组件刷新用户信息
            try {
              downloadAndOpen(item.highDefinition, 'localEmbedImageToMockup', item.config);
            } catch (error) {
              console.error('下载打开失败:', error);
              this.$message.error('下载打开失败');
            }
          } else if (res.code === 1002) {
            this.$message.error('余额不足，请先充值');
          } else {
            this.$message.error(res.message);
          }
        });
      }
    }
  }
};
</script>

